+        description: 'Show help information',
+        type: 'boolean',
+        default: false
+      },
+      {
+        name: 'version',
+        short: 'V',
+        description: 'Show version number',
+        type: 'boolean',
+        default: false
+      },
+      {
+        name: 'verbose',
+        short: 'v',
+        description: 'Enable verbose output',
+        type: 'boolean',
+        default: false
+      },
+      {
+        name: 'quiet',
+        short: 'q',
+        description: 'Suppress non-essential output',
+        type: 'boolean',
+        default: false
+      },
+      {
+        name: 'config',
+        short: 'c',
+        description: 'Path to configuration file',
+        type: 'string'
+      },
+      {
+        name: 'format',
+        short: 'f',
+        description: 'Output format (text, json, table)',
+        type: 'string',
+        default: 'text',
+        choices: ['text', 'json', 'table']
+      },
+      {
+        name: 'no-color',
+        description: 'Disable colored output',
+        type: 'boolean',
+        default: false
+      },
+      {
+        name: 'interactive',
+        short: 'i',
+        description: 'Enable interactive mode',
+        type: 'boolean',
+        default: true
+      }
+    ];
+  }
