+        if (booleanFlags.has(normalizedKey)) {
+          flags[normalizedKey] = true;
+        } else if (nextIndex < args.length && !args[nextIndex].startsWith('-')) {
+          flags[normalizedKey] = this.parseValue(args[nextIndex]);
+          nextIndex++;
+        } else {
+          flags[normalizedKey] = true;
+        }
