+    // String
+    return value;
+  }
+
+  private normalizeKey(key: string): string {
+    // Convert kebab-case to camelCase
+    return key.replace(/-([a-z])/g, (_, letter) => letter.toUpperCase());
+  }
+
+  private buildAliases(): Record<string, string> {
