+  /**
+   * Stop all transports
+   */
+  async stopAll(): Promise<void> {
+    if (!this.running) {
+      return;
+    }
+
+    this.logger.info('Stopping all transports');
+
+    const stopPromises = Array.from(this.transports.entries()).map(
