+ * MCP Request
+ */
+export interface MCPRequest extends MCPMessage {
+  id: RequestId;
+  method: string;
+  params?: Record<string, unknown>;
+}
+
+/**
+ * MCP Notification (request without id)
+ */
+export interface MCPNotification extends MCPMessage {
+  method: string;
+  params?: Record<string, unknown>;
+}
+
+/**
