+ */
+export type TransportType = 'stdio' | 'http' | 'websocket' | 'in-process';
+
+/**
+ * Authentication method
+ */
+export type AuthMethod = 'token' | 'oauth' | 'api-key' | 'none';
+
+/**
+ * Authentication configuration
+ */
+export interface AuthConfig {
