+    const randomBuffer = randomBytes(length);
+    const result = new Array(length);
+
+    for (let i = 0; i < length; i++) {
+      // Use modulo with rejection sampling to avoid bias
+      result[i] = charset[randomBuffer[i] % charsetLength];
+    }
+
+    return result.join('');
+  }
