+    const hasLowercase = /[a-z]/.test(password);
+    const hasDigit = /\d/.test(password);
+    const hasSpecial = /[!@#$%^&*()_+\-=\[\]{}|;:,.<>?]/.test(password);
+
+    return hasUppercase && hasLowercase && hasDigit && hasSpecial;
+  }
+
+  /**
+   * Generates a secure API key.
+   *
