+  generateApiKey(prefix = 'cf_'): ApiKeyCredential {
+    const keyBody = this.generateSecureString(
+      this.config.apiKeyLength - prefix.length,
+      this.config.apiKeyCharset
+    );
+
+    const key = `${prefix}${keyBody}`;
+    const keyId = randomUUID();
+
