+      // Check against blocked patterns
+      for (const pattern of this.blockedPatterns) {
+        if (pattern.test(arg)) {
+          throw new SafeExecutorError(
+            `Dangerous pattern detected in argument: ${arg}`,
+            'DANGEROUS_PATTERN',
+            undefined,
+            args
+          );
+        }
+      }
