+/**
+ * V3 Unified Swarm Coordinator Types
+ * Consolidated type definitions for the unified swarm coordination system
+ */
+
+import { EventEmitter } from 'events';
+
+// ===== CORE IDENTIFIERS =====
+
+export interface SwarmId {
+  id: string;
+  namespace: string;
+  version: string;
+  createdAt: Date;
+}
+
+export interface AgentId {
+  id: string;
+  swarmId: string;
+  type: AgentType;
+  instance: number;
+}
+
+export interface TaskId {
+  id: string;
+  swarmId: string;
+  sequence: number;
+  priority: TaskPriority;
+}
+
+// ===== TOPOLOGY TYPES =====
+
+export type TopologyType = 'mesh' | 'hierarchical' | 'centralized' | 'hybrid';
+
+export interface TopologyConfig {
+  type: TopologyType;
+  maxAgents: number;
+  replicationFactor?: number;
+  partitionStrategy?: 'hash' | 'range' | 'round-robin';
+  failoverEnabled?: boolean;
+  autoRebalance?: boolean;
+}
+
+export interface TopologyState {
+  type: TopologyType;
+  nodes: TopologyNode[];
+  edges: TopologyEdge[];
+  leader?: string;
+  partitions: TopologyPartition[];
+}
+
+export interface TopologyNode {
+  id: string;
+  agentId: string;
+  role: 'queen' | 'worker' | 'coordinator' | 'peer';
+  status: 'active' | 'inactive' | 'syncing' | 'failed';
+  connections: string[];
+  metadata: Record<string, unknown>;
+}
+
+export interface TopologyEdge {
+  from: string;
+  to: string;
+  weight: number;
+  bidirectional: boolean;
+  latencyMs?: number;
+}
+
+export interface TopologyPartition {
+  id: string;
+  nodes: string[];
+  leader: string;
+  replicaCount: number;
+}
+
+// ===== AGENT TYPES =====
+
+export type AgentType =
+  | 'coordinator'
+  | 'researcher'
+  | 'coder'
+  | 'analyst'
+  | 'architect'
+  | 'tester'
+  | 'reviewer'
+  | 'optimizer'
+  | 'documenter'
+  | 'monitor'
+  | 'specialist'
+  | 'queen'
+  | 'worker';
+
+export type AgentStatus =
+  | 'initializing'
+  | 'idle'
+  | 'busy'
+  | 'paused'
+  | 'error'
+  | 'offline'
+  | 'terminating'
+  | 'terminated';
+
+export interface AgentCapabilities {
+  codeGeneration: boolean;
+  codeReview: boolean;
+  testing: boolean;
+  documentation: boolean;
+  research: boolean;
+  analysis: boolean;
+  coordination: boolean;
+  languages: string[];
+  frameworks: string[];
+  domains: string[];
+  tools: string[];
