+
+/**
+ * MCP prompt argument
+ */
+export interface MCPPromptArgument {
+  name: string;
+  description?: string;
+  required?: boolean;
+}
+
+/**
+ * MCP prompt result
+ */
+export interface MCPPromptResult {
+  messages: MCPPromptMessage[];
+}
+
+/**
+ * MCP prompt message
+ */
+export interface MCPPromptMessage {
+  role: 'user' | 'assistant';
+  content: MCPContent;
